mapper.select:
select pss.process_key_id, pss.process_id, pss.product_id, pss.process_name, pss.unit_price, pss.cost_time, pro.product_style_name, pro.product_name from process pss left join product pro on pro.product_id = pss.product_id and pro.delete_flg =false where pss.delete_flg = false
and pss.product_id = #{productId,jdbcType=BIGINT}
and pss.process_id = #{processId,jdbcType=BIGINT}
and pss.process_name like CONCAT('%',#{processName, jdbcType=VARCHAR},'%')
order by pro.product_style_name,pro.product_name,pss.process_id

SELECT COUNT(*)
FROM process
WHERE
delete_flg = false

    AND product_id = #{productId,jdbcType=INTEGER}


    AND process_id = #{processId,jdbcType=INTEGER}
